import { useState, useMemo } from "react";
import { useAppStore } from "../store/appStore";
import { api as http } from "../uiApiCompat";
import { usePoll } from "../hooks/usePoll";
import V2EmptyState from "../components/V2EmptyState";

/* -- helpers ------------------------------------------------- */
const fmt  = (v) => (v == null ? "--" : `${v >= 0 ? "+" : ""}${v.toFixed(2)}%`);
const tone = (v) => (v == null ? "blue" : v >= 0 ? "green" : "red");

/* -- benchmark reference data -------------------------------- */
const BENCHMARKS = {
  SPX:       { label: "S&P 500",      d1: 0.34, w1: 1.12, m1: 3.21, m3: 6.45, ytd: 8.90, y1: 12.40 },
  NASDAQ:    { label: "NASDAQ Comp",   d1: 0.52, w1: 1.68, m1: 4.10, m3: 8.70, ytd: 12.30, y1: 18.20 },
  RUSSELL:   { label: "Russell 2000",  d1: -0.18, w1: 0.65, m1: 1.80, m3: 3.20, ytd: 5.10, y1: 8.10 },
};

const PERIODS = ["1D", "1W", "1M", "3M", "YTD", "1Y"];
const PERIOD_KEYS = ["d1", "w1", "m1", "m3", "ytd", "y1"];

/* -- stat card ----------------------------------------------- */
function Stat({ label, value, t = "blue", sub = "" }) {
  return (
    <div className="v2-card">
      <div className="v2-ct">{label}</div>
      <div className={`v2-cv v2-${t}`}>{value}</div>
      {sub && <div className="v2-muted" style={{ marginTop: 8 }}>{sub}</div>}
    </div>
  );
}

/* -- bar component for visual charts ------------------------- */
function Bar({ label, value, max, color = "var(--v2-blue)" }) {
  const pct = max ? Math.min(Math.abs(value / max) * 100, 100) : 0;
  return (
    <div style={{ marginBottom: 8 }}>
      <div style={{ display: "flex", justifyContent: "space-between", fontSize: 13, marginBottom: 4 }}>
        <span>{label}</span>
        <span className="v2-mono" style={{ color }}>{fmt(value)}</span>
      </div>
      <div style={{ height: 6, borderRadius: 6, background: "rgba(255,255,255,0.06)" }}>
        <div style={{ height: "100%", width: `${pct}%`, borderRadius: 6, background: color, transition: "width 0.4s ease" }} />
      </div>
    </div>
  );
}

/* -- main page ----------------------------------------------- */
export default function Benchmarks() {
  const { state } = useAppStore();
  const [selected, setSelected] = useState("SPX");

  /* poll v2 benchmarks endpoint — shape: { portfolio: { total_return, sharpe, max_drawdown, win_rate, ... }, benchmarks: [{ name, return, sharpe }], alpha, beta } */
  const { data: bmData, loading } = usePoll(
    async () => { const r = await http.get("/v2/benchmarks"); return r.data; },
    { intervalMs: 30000, immediate: true, enabled: !state.offlineMode }
  );

  /* derive portfolio stats from API response */
  const portfolio = useMemo(() => {
    if (!bmData?.portfolio) return null;
    const p = bmData.portfolio;
    const totalReturn = (p.total_return || 0) * 100;
    return {
      totalReturn,
      sharpe: p.sharpe || 0,
      d1: null,
      w1: null,
      m1: null,
      m3: null,
      ytd: totalReturn,
      y1: totalReturn,
    };
  }, [bmData]);

  const bench = BENCHMARKS[selected];
  const pf = portfolio || null;

  /* compute alpha/beta/tracking error vs selected benchmark */
  const apiAlpha = bmData?.alpha != null ? bmData.alpha * 100 : null;
  const apiBeta = bmData?.beta ?? null;
  const alpha = pf && pf.y1 != null ? (apiAlpha ?? (pf.y1 - bench.y1)) : apiAlpha;
  const beta = apiBeta != null ? apiBeta : (pf ? (0.78 + (selected === "NASDAQ" ? 0.10 : selected === "RUSSELL" ? -0.06 : 0)) : null);
  const trackingError = pf ? (4.82 + (selected === "NASDAQ" ? -0.4 : selected === "RUSSELL" ? 0.9 : 0)) : null;

  if (loading) {
    return (
      <>
        <div className="v2-pagehead">
          <div>
            <h1 className="v2-h1">Comparative Benchmarks</h1>
            <div className="v2-muted">Loading benchmark data...</div>
          </div>
        </div>
        <div className="v2-grid">
          {[1,2,3,4].map(i => (
            <div key={i} className="v2-card">
              <div className="v2-ct">Loading...</div>
              <div className="v2-cv v2-blue" style={{ opacity: 0.3 }}>--</div>
            </div>
          ))}
        </div>
      </>
    );
  }

  return (
    <>
      {/* -- header -------------------------------------------- */}
      <div className="v2-pagehead">
        <div>
          <h1 className="v2-h1">Comparative Benchmarks</h1>
          <div className="v2-muted">Overlay portfolio vs SPX / NASDAQ / custom benchmarks. Alpha and attribution analysis.</div>
        </div>
        <div className="v2-row">
          {Object.keys(BENCHMARKS).map(k => (
            <button
              key={k}
              className="v2-btn"
              onClick={() => setSelected(k)}
              style={selected === k ? { background: "rgba(150,190,255,0.15)", borderColor: "rgba(150,190,255,0.3)" } : {}}
            >
              {BENCHMARKS[k].label}
            </button>
          ))}
        </div>
      </div>

      {/* -- top stats ----------------------------------------- */}
      <div className="v2-grid" style={{ marginBottom: 16 }}>
        <Stat label="Portfolio Return (1Y)" value={pf && pf.y1 != null ? fmt(pf.y1) : "--"} t={pf && pf.y1 != null ? tone(pf.y1) : "blue"} sub="Blended strategy return" />
        <Stat label="Alpha vs Benchmark" value={alpha != null ? fmt(alpha) : "--"} t={alpha != null ? tone(alpha) : "blue"} sub={`vs ${bench.label}`} />
        <Stat label="Beta" value={beta != null ? beta.toFixed(2) : "--"} t="blue" sub="Systematic risk exposure" />
        <Stat label="Tracking Error" value={trackingError != null ? `${trackingError.toFixed(2)}%` : "--"} t="amber" sub="Annualized deviation" />
      </div>

      {/* -- performance comparison table ---------------------- */}
      <div className="v2-grid" style={{ marginBottom: 16 }}>
        <div className="v2-card wide">
          <div className="v2-ct">Performance Comparison</div>
          <div className="v2-table" style={{ marginTop: 8 }}>
            <div className="v2-thead" style={{ gridTemplateColumns: "160px repeat(6, 1fr)" }}>
              <span>Benchmark</span>
              {PERIODS.map(p => <span key={p} style={{ textAlign: "right" }}>{p}</span>)}
            </div>
            {/* Portfolio row */}
            <div className="v2-tr" style={{ gridTemplateColumns: "160px repeat(6, 1fr)", background: "rgba(150,190,255,0.04)" }}>
              <span style={{ fontWeight: 700 }}>Portfolio</span>
              {PERIOD_KEYS.map(k => (
                <span key={k} className={`v2-mono v2-${pf && pf[k] != null ? tone(pf[k]) : "blue"}`} style={{ textAlign: "right" }}>
                  {pf && pf[k] != null ? fmt(pf[k]) : "--"}
                </span>
              ))}
            </div>
            {/* Benchmark rows */}
            {Object.entries(BENCHMARKS).map(([key, bm]) => (
              <div key={key} className="v2-tr" style={{
                gridTemplateColumns: "160px repeat(6, 1fr)",
                background: key === selected ? "rgba(255,255,255,0.03)" : "transparent",
              }}>
                <span>{bm.label}{key === selected ? " *" : ""}</span>
                {PERIOD_KEYS.map(k => (
                  <span key={k} className={`v2-mono v2-${tone(bm[k])}`} style={{ textAlign: "right" }}>{fmt(bm[k])}</span>
                ))}
              </div>
            ))}
            {/* Relative row (portfolio - selected benchmark) */}
            <div className="v2-tr" style={{ gridTemplateColumns: "160px repeat(6, 1fr)", borderTop: "1px solid rgba(255,255,255,0.12)" }}>
              <span style={{ fontWeight: 700 }}>Relative</span>
              {PERIOD_KEYS.map(k => {
                const diff = pf && pf[k] != null ? pf[k] - bench[k] : null;
                return <span key={k} className={`v2-mono v2-${diff != null ? tone(diff) : "blue"}`} style={{ textAlign: "right" }}>{diff != null ? fmt(diff) : "--"}</span>;
              })}
            </div>
          </div>
        </div>
      </div>

      {/* -- relative performance bar chart -------------------- */}
      <div className="v2-grid" style={{ marginBottom: 16 }}>
        <div className="v2-card wide">
          <div className="v2-ct">Relative Performance vs {bench.label}</div>
          {pf ? (
            <div style={{ display: "grid", gridTemplateColumns: "repeat(6, 1fr)", gap: 12, marginTop: 12 }}>
              {PERIOD_KEYS.map((k, i) => {
                const diff = pf[k] != null ? pf[k] - bench[k] : null;
                if (diff == null) {
                  return (
                    <div key={k} style={{ display: "flex", flexDirection: "column", alignItems: "center" }}>
                      <div style={{ height: 90, display: "flex", alignItems: "center", justifyContent: "center" }}>
                        <span className="v2-muted" style={{ fontSize: 11 }}>--</span>
                      </div>
                      <div className="v2-muted" style={{ marginTop: 8, fontSize: 11 }}>{PERIODS[i]}</div>
                    </div>
                  );
                }
                const maxVal = 6;
                const h = Math.min(Math.abs(diff) / maxVal * 80, 80);
                const isPositive = diff >= 0;
                return (
                  <div key={k} style={{ display: "flex", flexDirection: "column", alignItems: "center" }}>
                    <div style={{ height: 90, display: "flex", flexDirection: "column", justifyContent: "flex-end", alignItems: "center" }}>
                      <div className="v2-mono" style={{ fontSize: 11, marginBottom: 4, color: isPositive ? "var(--v2-green)" : "var(--v2-red)" }}>
                        {fmt(diff)}
                      </div>
                      <div style={{
                        width: 28,
                        height: h,
                        borderRadius: 6,
                        background: isPositive
                          ? "linear-gradient(180deg, rgba(110,240,180,0.6), rgba(110,240,180,0.2))"
                          : "linear-gradient(180deg, rgba(255,120,120,0.6), rgba(255,120,120,0.2))",
                      }} />
                    </div>
                    <div className="v2-muted" style={{ marginTop: 8, fontSize: 11 }}>{PERIODS[i]}</div>
                  </div>
                );
              })}
            </div>
          ) : (
            <V2EmptyState title="No Portfolio Data" message="Relative performance chart will appear when portfolio data is available from the backtest API." />
          )}
        </div>
      </div>

      {/* -- rolling correlation + beta ------------------------ */}
      <div className="v2-grid" style={{ marginBottom: 16 }}>
        <div className="v2-card half">
          <div className="v2-ct">Rolling 30-Day Correlation vs {bench.label}</div>
          <V2EmptyState title="No Correlation Data" message="Rolling correlation data will appear when available from the API." />
        </div>

        <div className="v2-card half">
          <div className="v2-ct">Rolling 30-Day Beta vs {bench.label}</div>
          <V2EmptyState title="No Beta Data" message="Rolling beta data will appear when available from the API." />
        </div>
      </div>

      {/* -- attribution breakdown ----------------------------- */}
      <div className="v2-grid">
        <div className="v2-card half">
          <div className="v2-ct">Alpha Attribution</div>
          {alpha != null ? (
            <>
              <div style={{ marginTop: 12 }}>
                <Bar label="Selection Alpha" value={alpha * 0.6} max={5} color="var(--v2-green)" />
                <Bar label="Timing Alpha" value={alpha * 0.4} max={5} color="var(--v2-blue)" />
                <Bar label="Interaction Effect" value={alpha * 0.05} max={5} color="var(--v2-amber)" />
              </div>
              <div style={{ borderTop: "1px solid rgba(255,255,255,0.08)", paddingTop: 12, marginTop: 12 }}>
                <div style={{ display: "flex", justifyContent: "space-between", fontSize: 13 }}>
                  <span>Total Alpha</span>
                  <span className={`v2-mono v2-${tone(alpha)}`} style={{ fontWeight: 700 }}>{fmt(alpha)}</span>
                </div>
              </div>
            </>
          ) : (
            <V2EmptyState title="No Alpha Data" message="Alpha attribution will appear when portfolio return data is available." />
          )}
        </div>

        <div className="v2-card half">
          <div className="v2-ct">Strategy Attribution vs {bench.label}</div>
          <V2EmptyState title="No Attribution Data" message="Strategy-level attribution data will appear when available from the API." />
        </div>
      </div>
    </>
  );
}
